CREATE TYPE user_role AS ENUM ('Admin','Sales','Warehouse','Accounts');
CREATE TYPE challan_status AS ENUM ('Draft','Confirmed','Cancelled');
CREATE TYPE movement_type AS ENUM ('IN','OUT');
CREATE TABLE users (id SERIAL PRIMARY KEY,name VARCHAR(120) NOT NULL,email VARCHAR(255) UNIQUE NOT NULL,password_hash TEXT NOT NULL,role user_role NOT NULL,is_active BOOLEAN NOT NULL DEFAULT true,created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE customers (id SERIAL PRIMARY KEY,name VARCHAR(150) NOT NULL,mobile VARCHAR(25) NOT NULL,email VARCHAR(255),business_name VARCHAR(200),gst_number VARCHAR(30),customer_type VARCHAR(50) NOT NULL,address TEXT,status VARCHAR(20) NOT NULL DEFAULT 'Active',follow_up_date DATE,notes TEXT,created_at TIMESTAMPTZ NOT NULL DEFAULT now(),updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE products (id SERIAL PRIMARY KEY,product_name VARCHAR(200) NOT NULL,sku VARCHAR(80) UNIQUE NOT NULL,category VARCHAR(100),unit_price NUMERIC(12,2) NOT NULL CHECK(unit_price>=0),current_stock INTEGER NOT NULL DEFAULT 0 CHECK(current_stock>=0),minimum_stock INTEGER NOT NULL DEFAULT 0 CHECK(minimum_stock>=0),warehouse_location VARCHAR(100),created_at TIMESTAMPTZ NOT NULL DEFAULT now(),updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE follow_ups (id SERIAL PRIMARY KEY,customer_id INTEGER NOT NULL REFERENCES customers(id) ON DELETE CASCADE,follow_up_date DATE NOT NULL,notes TEXT NOT NULL,created_by INTEGER NOT NULL REFERENCES users(id),created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE stock_movements (id SERIAL PRIMARY KEY,product_id INTEGER NOT NULL REFERENCES products(id),movement_type movement_type NOT NULL,quantity INTEGER NOT NULL CHECK(quantity>0),reason TEXT NOT NULL,created_by INTEGER NOT NULL REFERENCES users(id),created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE challans (id SERIAL PRIMARY KEY,challan_number VARCHAR(40) UNIQUE NOT NULL,customer_id INTEGER NOT NULL REFERENCES customers(id),status challan_status NOT NULL DEFAULT 'Draft',notes TEXT,created_by INTEGER NOT NULL REFERENCES users(id),created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE challan_items (id SERIAL PRIMARY KEY,challan_id INTEGER NOT NULL REFERENCES challans(id) ON DELETE CASCADE,product_id INTEGER NOT NULL REFERENCES products(id),product_name VARCHAR(200) NOT NULL,sku VARCHAR(80) NOT NULL,unit_price NUMERIC(12,2) NOT NULL,quantity INTEGER NOT NULL CHECK(quantity>0));
CREATE INDEX customers_search_idx ON customers USING gin(to_tsvector('simple',coalesce(name,'')||' '||coalesce(mobile,'')||' '||coalesce(business_name,'')));
CREATE INDEX stock_movements_product_idx ON stock_movements(product_id,created_at DESC);
